import { useEffect, useState } from "react";

interface PageLoaderProps {
  isLoading?: boolean;
  delay?: number;
}

export function PageLoader({ isLoading = true, delay = 300 }: PageLoaderProps) {
  const [showLoader, setShowLoader] = useState(isLoading);
  const [isHidden, setIsHidden] = useState(false);

  useEffect(() => {
    if (!isLoading) {
      const hideTimer = setTimeout(() => {
        setIsHidden(true);
        const removeTimer = setTimeout(() => {
          setShowLoader(false);
        }, 500);
        return () => clearTimeout(removeTimer);
      }, delay);

      return () => clearTimeout(hideTimer);
    } else {
      // eslint-disable-next-line react-hooks/set-state-in-effect -- intentional: show loader when loading starts
      setShowLoader(true);
      setIsHidden(false);
    }
  }, [isLoading, delay]);

  if (!showLoader) return null;

  return (
    <div
      className={`fixed inset-0 z-[9999] flex items-center justify-center bg-[linear-gradient(135deg,var(--color-page)_0%,var(--color-page-strong)_100%)] transition-opacity duration-500 ease-[cubic-bezier(0.25,1,0.25,1)] ${isHidden ? "opacity-0 pointer-events-none" : "opacity-100 pointer-events-auto"}`}
      aria-hidden={isHidden}
    >
      <div className="flex flex-col items-center gap-6">
        <div className="relative w-12 h-12">
          <div className="absolute inset-0 rounded-full border-[3px] border-transparent border-t-accent border-r-accent-secondary animate-[page-loader-spin_1.2s_linear_infinite]"></div>
          <div className="absolute inset-[8px] rounded-full border-[3px] border-transparent border-t-accent-secondary animate-[page-loader-spin_1.8s_linear_infinite_reverse]"></div>
          <div className="absolute inset-[16px] rounded-full border-[3px] border-transparent border-t-accent animate-[page-loader-spin_2.4s_linear_infinite]"></div>
        </div>
        <p className="font-sans text-sm font-medium text-text-muted tracking-[0.08em] uppercase animate-[page-loader-fade_1.6s_ease-in-out_infinite]">Loading</p>
      </div>
    </div>
  );
}
